import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as s,o as c,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/ocr.md","filePath":"ur/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"ur/Other/ocr.md"};function u(h,e,g,m,b,y){return c(),n("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR images، scans، اور document screenshots سے text extract کرتا ہے۔</p><p>recognition کے بعد آپ result copy کر سکتے ہیں، اسے <code>Markdown</code>، <code>PDF</code>، یا <code>Word</code> کے طور پر export کر سکتے ہیں، یا multiple formats کو ایک package بنا کر download کر سکتے ہیں۔</p><h2 id="ocr-کیا-کر-سکتا-ہے" tabindex="-1">OCR کیا کر سکتا ہے <a class="header-anchor" href="#ocr-کیا-کر-سکتا-ہے" aria-label="Permalink to &quot;OCR کیا کر سکتا ہے&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>images، screenshots، اور scans سے text extract کرتا ہے۔</td></tr><tr><td>Document layout recognition</td><td>tables، formulas، stamps، اور mixed text-image layouts کے لیے بہتر۔</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR، Microsoft Azure Vision، اور Google Vision support کرتا ہے۔</td></tr><tr><td>Copy results</td><td>processing کے بعد recognized text copy کریں۔</td></tr><tr><td>Export files</td><td><code>Markdown</code>، <code>PDF</code>، اور <code>Word</code> export کریں۔</td></tr><tr><td>Batch packaging</td><td>multiple files recognize ہونے کے بعد results کو package کے طور پر download کریں۔</td></tr></tbody></table><h2 id="پہلے-ocr-services-configure-کریں" tabindex="-1">پہلے OCR Services Configure کریں <a class="header-anchor" href="#پہلے-ocr-services-configure-کریں" aria-label="Permalink to &quot;پہلے OCR Services Configure کریں&quot;">​</a></h2><p>کھولیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>جن services کو استعمال کرنا ہے ان کے credentials بھریں:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>recommended first choice۔ documents، images، tables، اور mixed layouts کے لیے اچھا۔</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> اور <code>Azure Vision API Key</code></td><td>اگر آپ پہلے سے Microsoft cloud services استعمال کرتے ہیں تو useful۔</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>۔ Service account <code>JSON</code> صرف quota query کے لیے استعمال ہوتا ہے۔</td><td>اگر آپ Google Cloud services استعمال کرتے ہیں تو useful۔</td></tr></tbody></table><p>credentials بھرنے کے بعد save کریں۔</p><p>initial testing کے لیے صرف ایک service configure کرنا کافی ہے۔ تینوں ضروری نہیں۔</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup کے دو parts ہیں:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR استعمال کرنا</td><td><code>Cloud Vision API</code> enable کریں، پھر <code>API Key</code> بنائیں۔</td></tr><tr><td>usage query کرنا</td><td>service account بنائیں، <code>Monitoring Viewer</code> grant کریں، پھر service account <code>JSON</code> download کریں۔</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="google-کو-ocr-کے-لیے-استعمال-کرنا" tabindex="-1">Google کو OCR کے لیے استعمال کرنا <a class="header-anchor" href="#google-کو-ocr-کے-لیے-استعمال-کرنا" aria-label="Permalink to &quot;Google کو OCR کے لیے استعمال کرنا&quot;">​</a></h3><ol><li>Google Cloud Console کھولیں۔</li><li><code>APIs &amp; Services</code> میں جائیں۔</li><li><code>Library</code> کھولیں، <code>Cloud Vision API</code> تلاش کریں، اور enable کریں۔</li><li><code>Credentials</code> پر واپس جائیں۔</li><li><code>API Key</code> بنائیں۔</li><li>API Key کھولیں اور copy کریں۔</li><li>ImgBed میں <code>Google Vision API Key</code> میں paste کریں۔</li><li>Save کریں۔</li></ol><p>اس کے بعد OCR dialog میں Google Vision منتخب کیا جا سکتا ہے۔</p><h3 id="google-usage-query" tabindex="-1">Google Usage Query <a class="header-anchor" href="#google-usage-query" aria-label="Permalink to &quot;Google Usage Query&quot;">​</a></h3><p>Quota query recognition کے لیے required نہیں۔</p><p>یہ صرف تقریباً دکھاتا ہے کہ پچھلے 30 دنوں میں Google Vision calls کتنی استعمال ہوئیں۔</p><ol><li>Google Cloud Console میں <code>IAM &amp; Admin</code> کھولیں۔</li><li><code>Service Accounts</code> کھولیں۔</li><li>service account بنائیں، مثلاً <code>vision-monitor</code>۔</li><li>اسے <code>Monitoring Viewer</code> role دیں۔</li><li>service account details کھولیں اور key بنائیں۔</li><li><code>JSON</code> منتخب کریں۔</li><li>generated JSON file download کریں۔</li><li>ImgBed پر واپس آ کر اسے service account <code>JSON</code> کے تحت import کریں (optional)۔</li><li>import successful ہونے کے بعد quota query پر کلک کریں۔</li></ol><p>import کے بعد ImgBed service account کے owning project کا نام دکھاتا ہے۔ usage query کرتے وقت ImgBed Google monitoring data پڑھ کر اس month کا call count دکھاتا ہے۔</p><p>مختصر:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition چلاتا ہے۔</td></tr><tr><td>Service account <code>JSON</code></td><td>Google Vision calls کی usage query کرتا ہے۔</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>service account کو usage data پڑھنے دیتا ہے۔</td></tr></tbody></table><h2 id="baidu-paddleocr-token-حاصل-کریں" tabindex="-1">Baidu PaddleOCR Token حاصل کریں <a class="header-anchor" href="#baidu-paddleocr-token-حاصل-کریں" aria-label="Permalink to &quot;Baidu PaddleOCR Token حاصل کریں&quot;">​</a></h2><p>Baidu PaddleOCR access token require کرتا ہے۔</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Baidu PaddleOCR page پر <code>API</code> call window کھولیں، token لینے کے لیے click کریں، پھر اسے copy کریں۔</p><p>ImgBed پر واپس آ کر <code>PaddleOCR Token</code> میں paste کریں اور save کریں۔</p><h2 id="recognition-شروع-کریں" tabindex="-1">Recognition شروع کریں <a class="header-anchor" href="#recognition-شروع-کریں" aria-label="Permalink to &quot;Recognition شروع کریں&quot;">​</a></h2><p>File Management میں image یا document screenshot منتخب کریں اور <code>OCR</code> پر کلک کریں۔</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>dialog میں recognition service اور model منتخب کریں۔</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>recommended default۔ documents، tables، formulas، stamps، اور mixed layouts کے لیے اچھا۔</td></tr><tr><td><code>PP-OCRv5</code></td><td>simple images، ordinary text، اور lightweight recognition۔</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>multilingual، complex images، اور chart-like content۔</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>زیادہ complex document pages اور layout recovery۔</td></tr></tbody></table><p>یقین نہ ہو تو <code>PP-StructureV3</code> سے شروع کریں۔</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>image rotated یا skewed ہو تو استعمال کریں۔</td></tr><tr><td>Document flattening</td><td>photographed documents میں curvature یا tilt ہو تو استعمال کریں۔</td></tr><tr><td>Layout detection</td><td>headings، paragraphs، tables، اور image structure preserve کرنا ہو تو استعمال کریں۔</td></tr><tr><td>Chart recognition</td><td>image میں charts یا complex structures ہوں تو استعمال کریں۔</td></tr><tr><td>Beautify <code>Markdown</code></td><td>exported Markdown کو زیادہ readable بناتا ہے۔</td></tr></tbody></table><p>regular screenshots کے لیے options minimal رکھیں۔ document scans کے لیے document-related options زیادہ enable کریں۔</p><h2 id="results-دیکھیں" tabindex="-1">Results دیکھیں <a class="header-anchor" href="#results-دیکھیں" aria-label="Permalink to &quot;Results دیکھیں&quot;">​</a></h2><p>recognition finish ہونے کے بعد dialog result دکھاتا ہے۔</p><p>آپ اسے directly copy کر سکتے ہیں یا export formats منتخب کر سکتے ہیں۔</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>document pages کے لیے exported <code>PDF</code> page appearance preserve کر سکتا ہے جبکہ text searchable رہتا ہے۔ یہ scans archive کرنے اور بعد میں content تلاش کرنے کے لیے useful ہے۔</p><h2 id="export-format-منتخب-کرنا" tabindex="-1">Export Format منتخب کرنا <a class="header-anchor" href="#export-format-منتخب-کرنا" aria-label="Permalink to &quot;Export Format منتخب کرنا&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>notes، documentation systems، اور later editing۔</td></tr><tr><td><code>PDF (.pdf)</code></td><td>page appearance اور scanned document results preserve کرنا۔</td></tr><tr><td><code>Word (.docx)</code></td><td>layout editing، text modification، اور others کو handoff۔</td></tr><tr><td>Export all</td><td>multiple formats اور original image save کرتا ہے، important archives کے لیے مناسب۔</td></tr></tbody></table><p>صرف text چاہیے ہو تو Markdown export کریں۔</p><p>page appearance چاہیے ہو تو PDF یا Word استعمال کریں۔</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>exported Word documents office software میں open اور edit ہو سکتے ہیں۔</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>کچھ documents Word output میں recognized images، headings، اور paragraphs شامل کرتے ہیں۔</p><p>recognition quality original image clarity، model choice، اور document complexity پر depend کرتی ہے۔</p><h2 id="ocr-کے-لیے-بہترین-file-types" tabindex="-1">OCR کے لیے بہترین File Types <a class="header-anchor" href="#ocr-کے-لیے-بہترین-file-types" aria-label="Permalink to &quot;OCR کے لیے بہترین File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>directly recognize کریں۔</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> کو ترجیح دیں۔</td></tr><tr><td>Photographed documents</td><td>orientation correction اور document flattening enable کریں۔</td></tr><tr><td>Tables, formulas, stamps</td><td>structured models کو ترجیح دیں۔</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> عموماً کافی ہے۔</td></tr></tbody></table><p>زیادہ clear images اور سیدھا text عموماً بہتر results دیتے ہیں۔</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>چیک کریں کہ service token یا key save ہو چکی ہے۔</td></tr><tr><td>Recognition slow ہے</td><td>complex documents اور large images زیادہ وقت لیتے ہیں۔</td></tr><tr><td>Table incomplete ہے</td><td>structured model try کریں۔</td></tr><tr><td>Text میں mistakes ہیں</td><td>blur، glare، اور skew errors بڑھاتے ہیں۔ clearer image try کریں۔</td></tr><tr><td>Word output میں بہت سی images ہیں</td><td>structured models کچھ recognized images preserve کر سکتے ہیں۔ یہ normal ہے۔</td></tr></tbody></table><h3 id="google-quota-query-fail-ہوتی-ہے" tabindex="-1">Google Quota Query Fail ہوتی ہے <a class="header-anchor" href="#google-quota-query-fail-ہوتی-ہے" aria-label="Permalink to &quot;Google Quota Query Fail ہوتی ہے&quot;">​</a></h3><p>چیک کریں:</p><ol><li>Service account <code>JSON</code> import ہو چکا ہے۔</li><li>service account کے پاس <code>Monitoring Viewer</code> role ہے۔</li><li>project کے لیے <code>Cloud Vision API</code> enabled ہے۔</li></ol><p>اگر آپ کو صرف OCR چاہیے اور usage query نہیں، تو service account JSON ignore کر کے صرف <code>Google Vision API Key</code> بھر سکتے ہیں۔</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings کھولیں</span></span>
<span class="line"><span>-&gt; Other Settings کھولیں</span></span>
<span class="line"><span>-&gt; OCR service credentials بھریں</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; File Management پر واپس جائیں</span></span>
<span class="line"><span>-&gt; file منتخب کریں اور OCR پر کلک کریں</span></span>
<span class="line"><span>-&gt; model منتخب کریں</span></span>
<span class="line"><span>-&gt; recognition کا انتظار کریں</span></span>
<span class="line"><span>-&gt; results copy کریں یا Markdown / PDF / Word export کریں</span></span></code></pre></div>`,67)])])}const C=s(p,[["render",u]]);export{v as __pageData,C as default};
